export class TPlanCurso extends TRecurso {
	// PK
	get iplan(): string { return this.f.iplan }
	set iplan(v: any) { this.f.iplan = val2Str(v) }

	// FK
	get icurso(): string { return this.f.icurso }
	set icurso(v: any) { this.f.icurso = val2Str(v) }
	get itema(): string { return this.f.itema }
	set itema(v: any) { this.f.itema = val2Str(v) }
	/* get irecurso(): number { return this.f.irecurso }
	set irecurso(v: any) { this.f.irecurso = val2Int(v) } */

	// PROPIEDADES
	get titulo(): string { return this.f.titulo }
	set titulo(v: any) { this.f.titulo = val2Str(v) }

	// CAPAC_RECURSOS (detalle por IRECURSO)
	get recurso(): TRecurso { return this.f.recurso }
	set recurso(v: any) { this.f.recurso = val2TObject(v, TRecurso) }
	// CAPAC_ATRIBUTOS_PLANES
	get atributosplan(): TArray<TAtributosPlan> { return this.f.atributosplan }
	set atributosplan(v: any) { this.f.atributosplan = val2TArray(Array.isArray(v) ? v.filter(Boolean) : v, TAtributosPlan) }
	// CAPAC_ESTRUCTURAS_CURSOS (solo consulta contextual)
	get estructuranivel(): TEstructuraCurso { return this.f.estructuranivel }
	set estructuranivel(v: any) { this.f.estructuranivel = val2TObject(v, TEstructuraCurso) }

	get atributos(): TArray<TAtributosPlan | TAtributoRecurso> { return this.f.atributos }
	set atributos(v: any) {
		const lista = Array.isArray(v) ? v : [];
		this.f.atributos = new TArray<TAtributosPlan | TAtributoRecurso>(lista.map((item: TAtributosPlan | TAtributoRecurso) => "irecurso" in item ? val2TObject(item, TAtributoRecurso) : val2TObject(item, TAtributosPlan)))
	}

	// helpers
	get qnivel(): number { return this.iplan ? String(this.iplan).split(".").filter(Boolean).length : 0 }
}

export class TPlanCursoServer extends TCursoDetalleServer<TPlanCurso> {
	get NTbl(): string { return tablas.ntblCapacPlanesCursos }
	get Klass(): typeof TPlanCurso { return TPlanCurso }
	get PrimaryKeys(): Array<string> { return ["iplan", "icurso"] }
	JData2HighDetail = (): iInfoPlanCurso => ({ tema: { todo }, atributosplan: { todo }, estructuranivel: {}, recurso: { tdrecurso: {} } })
	getOrderBy(Alias: string): string {
		const A = `${Alias}.IPLAN`
		const jsonArr = `'["' + REPLACE(${A}, '.', '","') + '"]'`
		return Array.from({ length: 8 }, (_, i) => `COALESCE(TRY_CAST(JSON_VALUE(${jsonArr}, '$[${i}]') AS INT), -1)`).join(", ")
	}
	private filterAtributosConValor(atributos: TArray<TAtributosPlan> | null | undefined): TArray<TAtributosPlan> {
		const list = (atributos as TArray<TAtributosPlan> | null | undefined) ?? new TArray<TAtributosPlan>();
		const kept = list.filter((a) => a != null && String((a as TAtributosPlan).valor ?? "").trim().length > 0);
		return new TArray<TAtributosPlan>(kept);
	}
	PromiseInsertQry(src: TCurso, lista: TArray<TPlanCurso>): Array<Promise<TObjectQuery>> {
		return this.deepPromiseInsertQry(src, lista, ["icurso"], (item) => {
			item.atributosplan = this.filterAtributosConValor(item.atributosplan);
			return [[TAtributosPlanServer, item.atributosplan]];
		});
	}
	async InsertQryDetalle(plancurso: TPlanCurso): Promise<TObjectQuery> {
		plancurso.atributosplan = this.filterAtributosConValor(plancurso.atributosplan);
		return this.syncDetails(plancurso, [TAtributosPlanServer, plancurso.atributosplan]);
	}
	nestedConfig(JData: iInfoPlanCurso): TNestedSqlCfgList {
		return [
			{ consulta: [TRecursoController, JData.recurso], comparacion: ["IRECURSO"], as: "recurso" },
			{ consulta: [TTemasController, JData.tema], comparacion: ["ITEMA"], as: "tema" },
			{ consulta: [TAtributosPlanServer, JData.atributosplan], comparacion: ["IPLAN", "ICURSO"], esLista, as: "atributosplan" },
			{ consulta: [TEstructuraCursoServer, JData.estructuranivel], comparacion: ["ICURSO"], as: "estructuranivel", where: (sub, parent) => `${sub}.QNIVEL = (LEN(${parent}.IPLAN) - LEN(REPLACE(${parent}.IPLAN, '.', '')) + 1)` },
		];
	}
}

